package main

var indexHTML = []byte(`<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>RED OPS 小红书内容运营系统</title>
  <style>
    :root{--bg:#f5f7fb;--panel:#fff;--soft:#f8fafc;--text:#151922;--muted:#667085;--line:#e5e9f0;--blue:#2563eb;--blue2:#edf3ff;--green:#0f8a4b;--green2:#eaf8ef;--amber:#a15c05;--amber2:#fff5dc;--red:#c83227;--red2:#fff0ed;--violet:#7148d8;--violet2:#f3efff;--radius:8px}
    *{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:Inter,"Noto Sans SC","PingFang SC","Microsoft YaHei",Arial,sans-serif;letter-spacing:0}.app{display:grid;grid-template-columns:244px minmax(0,1fr);min-height:100vh}.sidebar{position:sticky;top:0;height:100vh;padding:24px 16px;background:#101827;color:#aab4c5}.brand{padding:4px 12px 24px;border-bottom:1px solid rgba(255,255,255,.08)}.brand b{display:block;color:#fff;font-size:20px}.brand span{display:block;margin-top:8px;color:#93a0b4;font-size:12px}.nav{display:grid;gap:6px;margin-top:20px}.nav button{width:100%;min-height:40px;padding:8px 12px;border:0;border-radius:8px;background:transparent;color:#aab4c5;text-align:left;cursor:pointer;font-weight:600}.nav button.active,.nav button:hover{background:#1e2f4d;color:#fff}.account-card{position:absolute;left:16px;right:16px;bottom:20px;padding:14px;border-radius:8px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.08)}.topbar{position:sticky;top:0;z-index:5;display:flex;justify-content:space-between;gap:16px;align-items:center;min-height:72px;padding:16px 28px;background:rgba(255,255,255,.94);border-bottom:1px solid var(--line);backdrop-filter:blur(12px)}h1{margin:0;font-size:22px}.sub{margin:4px 0 0;color:var(--muted);font-size:13px}.content{padding:28px}.view{display:none}.view.active{display:block}.grid{display:grid;gap:16px}.metrics{grid-template-columns:repeat(4,minmax(160px,1fr))}.two{grid-template-columns:minmax(0,1fr) 390px}.three{grid-template-columns:repeat(3,minmax(0,1fr))}.card{background:var(--panel);border:1px solid var(--line);border-radius:var(--radius)}.pad{padding:20px}.head{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:18px 20px;border-bottom:1px solid var(--line)}h2,h3{margin:0;font-size:16px}.metric{padding:18px;min-height:108px}.metric span{color:var(--muted);font-size:13px}.metric strong{display:block;margin-top:12px;font-size:30px}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:36px;padding:8px 14px;border-radius:8px;border:1px solid var(--line);background:#fff;color:var(--text);cursor:pointer;font-weight:700;font-size:13px}.btn.primary{background:var(--blue);border-color:var(--blue);color:#fff}.btn.danger{background:var(--red2);border-color:#ffd1c9;color:var(--red)}.btn.ghost{background:transparent;color:var(--muted)}.pill{display:inline-flex;align-items:center;justify-content:center;min-height:26px;padding:4px 10px;border-radius:999px;font-size:12px;font-weight:700;white-space:nowrap}.green{color:var(--green);background:var(--green2)}.blue{color:var(--blue);background:var(--blue2)}.amber{color:var(--amber);background:var(--amber2)}.red{color:var(--red);background:var(--red2)}.violet{color:var(--violet);background:var(--violet2)}.gray{color:var(--muted);background:var(--soft)}.toolbar{display:flex;flex-wrap:wrap;align-items:center;justify-content:space-between;gap:12px;margin-bottom:16px;padding:14px;background:#fff;border:1px solid var(--line);border-radius:8px}.row-actions{display:flex;flex-wrap:wrap;gap:8px}.table-wrap{overflow:auto}table{width:100%;min-width:820px;border-collapse:collapse}th,td{padding:14px 16px;border-bottom:1px solid var(--line);text-align:left;font-size:13px;vertical-align:middle}th{background:var(--soft);color:var(--muted)}td:first-child{font-weight:700}.list{display:grid;gap:12px;padding:20px}.item{display:flex;align-items:center;justify-content:space-between;gap:12px;min-height:50px;padding:12px 14px;background:var(--soft);border-radius:8px}.item small{display:block;margin-top:4px;color:var(--muted)}input,select,textarea{width:100%;min-height:36px;padding:8px 12px;border:1px solid var(--line);border-radius:8px;background:var(--soft);color:var(--text);font:inherit}.field{display:grid;gap:8px}.field label{font-size:12px;color:var(--muted);font-weight:700}textarea{min-height:110px;resize:vertical;line-height:1.6}.drawer{display:grid;grid-template-columns:minmax(0,1fr) 390px;gap:16px;align-items:start}.sidepanel{position:sticky;top:92px}.preview{min-height:180px;padding:16px;background:var(--soft);border:1px solid var(--line);border-radius:8px;line-height:1.75}.modal-bg{position:fixed;inset:0;z-index:20;display:none;place-items:center;background:rgba(8,15,30,.45);padding:20px}.modal-bg.open{display:grid}.modal{width:min(560px,100%);background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 20px 60px rgba(20,30,50,.22)}.modal header,.modal footer{display:flex;justify-content:space-between;gap:12px;padding:18px 20px;border-bottom:1px solid var(--line)}.modal footer{border-top:1px solid var(--line);border-bottom:0;justify-content:flex-end}.modal-body{display:grid;gap:16px;padding:20px}.toast{position:fixed;right:24px;bottom:24px;z-index:30;display:none;padding:14px 16px;border-radius:8px;background:var(--green2);color:var(--green);border:1px solid #bfeacc;font-weight:700}.toast.show{display:block}.calendar{display:grid;grid-template-columns:repeat(7,minmax(130px,1fr));gap:10px;overflow:auto}.day{min-height:460px;padding:14px;background:#fff;border:1px solid var(--line);border-radius:8px}.event{margin-top:10px;padding:10px;border-radius:8px;font-size:12px;font-weight:700}@media(max-width:1120px){.app{grid-template-columns:1fr}.sidebar{position:relative;height:auto}.account-card{position:static;margin-top:18px}.nav{grid-template-columns:repeat(4,1fr)}.metrics,.two,.three,.drawer{grid-template-columns:1fr}.sidepanel{position:static}}@media(max-width:680px){.topbar{align-items:stretch;flex-direction:column}.content{padding:18px}.nav{grid-template-columns:repeat(2,1fr)}}
  </style>
</head>
<body>
<div class="app">
  <aside class="sidebar">
    <div class="brand"><b>RED OPS</b><span>小红书内容运营系统</span></div>
    <nav class="nav" id="nav"></nav>
    <div class="account-card" id="accountSummary"><b>未绑定账号</b><div style="margin-top:8px;color:#93a0b4;font-size:12px">请在账号管理中绑定</div></div>
  </aside>
  <main>
    <header class="topbar"><div><h1 id="title">工作台</h1><p class="sub" id="subtitle">今日内容生产、审核和发布概览</p></div><button class="btn primary" onclick="openKeywordModal()">新建关键词</button></header>
    <section class="content">
      <div id="dashboard" class="view active"></div>
      <div id="keywords" class="view"></div>
      <div id="insights" class="view"></div>
      <div id="generate" class="view"></div>
      <div id="review" class="view"></div>
      <div id="calendar" class="view"></div>
      <div id="accounts" class="view"></div>
      <div id="rules" class="view"></div>
    </section>
  </main>
</div>
<div class="modal-bg" id="keywordModal"><div class="modal"><header><h2>新建关键词</h2><button class="btn ghost" onclick="closeModal('keywordModal')">关闭</button></header><div class="modal-body"><div class="field"><label>关键词</label><input id="newKeyword" value="夏季油皮护肤"></div><div class="field"><label>类目</label><input id="newCategory" value="美妆"></div><div class="field"><label>采集样本数</label><input id="newLimit" type="number" value="20"></div></div><footer><button class="btn primary" onclick="createKeyword()">创建</button></footer></div></div>
<div class="modal-bg" id="accountModal"><div class="modal"><header><h2>绑定真实账号</h2><button class="btn ghost" onclick="closeModal('accountModal')">关闭</button></header><div class="modal-body"><div class="field"><label>账号名称</label><input id="accountName" placeholder="例如：品牌号 A"></div><div class="field"><label>账号类型</label><select id="accountType"><option>品牌号</option><option>企业号</option><option>个人号</option></select></div><div class="field"><label>授权状态</label><select id="accountAuth"><option>待绑定</option><option>正常</option><option>待确认</option></select></div><div class="field"><label>每日发布上限</label><input id="accountLimit" type="number" value="8"></div></div><footer><button class="btn primary" onclick="createAccount()">保存账号</button></footer></div></div>
<div class="modal-bg" id="importModal"><div class="modal"><header><h2>导入真实网页样本</h2><button class="btn ghost" onclick="closeModal('importModal')">关闭</button></header><div class="modal-body"><input type="hidden" id="importKeywordID"><p class="sub">优先粘贴从小红书网页复制出的搜索结果或笔记内容；也可以切到 JSON 精准导入。</p><div class="field"><label>导入方式</label><select id="importMode" onchange="toggleImportMode()"><option value="text">网页文本</option><option value="json">JSON 数组</option></select></div><div class="field" id="importTextField"><label>网页文本</label><textarea id="importRawText" style="min-height:240px" placeholder="从小红书搜索结果或笔记详情页复制文本，包含标题、链接、点赞/评论/收藏/浏览等信息"></textarea></div><div class="field" id="importJSONField" style="display:none"><label>样本 JSON</label><textarea id="importPosts" style="min-height:240px">[
  {
    "title": "油皮夏天真的别乱叠早C晚A",
    "content_summary": "真实体验、步骤拆解、评论关注适用肤质",
    "url": "https://www.xiaohongshu.com/example",
    "views": 128000,
    "likes": 8420,
    "comments": 516,
    "favorites": 2104,
    "published_at": "2026-06-18T19:30:00+08:00"
  }
]</textarea></div></div><footer><button class="btn primary" onclick="submitImport()">导入样本</button></footer></div></div>
<div class="modal-bg" id="rejectModal"><div class="modal"><header><h2>驳回并重新生成</h2><button class="btn ghost" onclick="closeModal('rejectModal')">关闭</button></header><div class="modal-body"><input type="hidden" id="rejectID"><div class="field"><label>驳回原因 *</label><textarea id="rejectReason" placeholder="例如：标题太夸张，缺少真实体验感"></textarea></div><div class="field"><label>重新生成要求</label><textarea id="rejectInstruction" placeholder="例如：保留产品卖点，减少促销语气，加入个人使用场景"></textarea></div></div><footer><button class="btn" onclick="closeModal('rejectModal')">取消</button><button class="btn danger" onclick="submitReject()">驳回并重新生成</button></footer></div></div>
<div class="toast" id="toast"></div>
<script>
var state={dashboard:null,accounts:[],keywords:[],contents:[],rules:null,publishTasks:[],settings:null,selectedContent:null};
var views=[
  ["dashboard","工作台","今日内容生产、审核和发布概览"],
  ["keywords","关键词监控","配置关键词、采集频率和运行状态"],
  ["insights","热点分析","查看爆文样本、热度指标和风格拆解"],
  ["generate","内容生成","基于热点洞察生成标题、正文、封面和标签"],
  ["review","审核中心","列表审核、驳回原因和重新生成闭环"],
  ["calendar","发布日历","按账号和时间管理草稿发布计划"],
  ["accounts","账号管理","管理授权账号、发布额度和账号规则"],
  ["rules","规则设置","配置品牌语气、合规规则和生成模板"]
];
document.getElementById("nav").innerHTML=views.map(function(v,i){return "<button class='"+(i===0?"active":"")+"' onclick=\"show('"+v[0]+"')\">"+v[1]+"</button>"}).join("");
function api(path,opts){opts=opts||{};opts.headers=Object.assign({"Content-Type":"application/json"},opts.headers||{});return fetch(path,opts).then(function(r){return r.json().then(function(j){if(!r.ok)throw new Error(j.error||"请求失败");return j})})}
function show(id){views.forEach(function(v){document.getElementById(v[0]).classList.toggle("active",v[0]===id)});[].forEach.call(document.querySelectorAll(".nav button"),function(b,i){b.classList.toggle("active",views[i][0]===id)});var v=views.find(function(x){return x[0]===id});document.getElementById("title").textContent=v[1];document.getElementById("subtitle").textContent=v[2];render();}
function toast(msg){var t=document.getElementById("toast");t.textContent=msg;t.classList.add("show");setTimeout(function(){t.classList.remove("show")},2200)}
function closeModal(id){document.getElementById(id).classList.remove("open")}function openKeywordModal(){document.getElementById("keywordModal").classList.add("open")}
function clsStatus(s){if(["running","approved","draft_saved","published","success","low"].includes(s))return"green";if(["pending_review","scheduled","pending"].includes(s))return"amber";if(["rejected","publish_failed","failed","high","error"].includes(s))return"red";if(["generated","regenerating","draft_saving","running"].includes(s))return"violet";return"gray"}
function label(s){return {running:"运行中",paused:"暂停",error:"异常",pending_review:"待审核",approved:"已通过",rejected:"已驳回",draft_saving:"草稿保存中",draft_saved:"已保存草稿",scheduled:"待发布",published:"已发布",publish_failed:"发布失败",pending:"待发布",success:"成功",failed:"失败",low:"低风险",high:"高风险"}[s]||s}
function pill(s){return "<span class='pill "+clsStatus(s)+"'>"+label(s)+"</span>"}
function fmtTime(t){if(!t)return "-";return new Date(t).toLocaleString("zh-CN",{hour12:false})}
function money(n){return n==null?"-":String(n)}
function load(){return api("/api/bootstrap").then(function(data){state.dashboard=data.dashboard;state.accounts=data.accounts||[];state.keywords=state.dashboard.keywords||[];state.contents=data.contents||[];state.rules=data.rules;return api("/api/publish-tasks")}).then(function(tasks){state.publishTasks=tasks||[];return api("/api/settings")}).then(function(settings){state.settings=settings;render()}).catch(function(e){toast(e.message)})}
function render(){renderAccountSummary();renderDashboard();renderKeywords();renderInsights();renderGenerate();renderReview();renderCalendar();renderAccounts();renderRules()}
function renderAccountSummary(){var a=state.accounts[0];var html=a?"<b>"+a.name+"</b><div style='margin-top:8px;color:#93a0b4;font-size:12px'>"+a.auth_status+"<br>今日排期 "+a.today_scheduled+" / "+a.daily_limit+"</div>":"<b>未绑定账号</b><div style='margin-top:8px;color:#93a0b4;font-size:12px'>请在账号管理中绑定</div>";document.getElementById('accountSummary').innerHTML=html}
function renderDashboard(){var d=state.dashboard||{};document.getElementById("dashboard").innerHTML="<div class='grid metrics'><div class='card metric'><span>今日采集</span><strong>"+(d.collected_today||0)+"</strong></div><div class='card metric'><span>待审核</span><strong>"+(d.pending_review||0)+"</strong></div><div class='card metric'><span>已排期</span><strong>"+(d.scheduled||0)+"</strong></div><div class='card metric'><span>发布失败</span><strong>"+(d.publish_failed||0)+"</strong></div></div><div class='grid two' style='margin-top:16px'><div class='card'><div class='head'><h2>待处理队列</h2><button class='btn' onclick=\"show('review')\">去审核</button></div><div class='list'>"+state.contents.slice(0,6).map(function(c){return"<div class='item'><div><b>"+c.title+"</b><small>"+(c.keyword||"")+" · "+(c.account_name||"")+"</small></div>"+pill(c.status)+"</div>"}).join("")+"</div></div><div class='card'><div class='head'><h2>发布排期</h2><button class='btn' onclick='runDue()'>扫描发布</button></div><div class='list'>"+state.publishTasks.slice(0,6).map(function(p){return"<div class='item'><div><b>"+fmtTime(p.scheduled_at)+"</b><small>"+(p.title||"")+" · "+(p.account_name||"")+"</small></div>"+pill(p.status)+"</div>"}).join("")+"</div></div></div>"}
function renderKeywords(){document.getElementById("keywords").innerHTML="<div class='toolbar'><div class='row-actions'><button class='btn primary' onclick='openKeywordModal()'>新增关键词</button><button class='btn' onclick='collectFirst()'>采集首个关键词</button></div></div><div class='card table-wrap'><table><thead><tr><th>关键词</th><th>类目</th><th>最近采集</th><th>样本</th><th>状态</th><th>操作</th></tr></thead><tbody>"+state.keywords.map(function(k){return"<tr><td>"+k.keyword+"</td><td>"+k.category+"</td><td>"+fmtTime(k.last_collected_at)+"</td><td>"+k.sample_limit+"</td><td>"+pill(k.status)+"</td><td class='row-actions'><button class='btn' onclick='collect("+k.id+")'>采集</button><button class='btn' onclick='openImport("+k.id+")'>导入</button><button class='btn' onclick='analyze("+k.id+")'>分析</button><button class='btn primary' onclick='quickGenerate("+k.id+")'>生成</button></td></tr>"}).join("")+"</tbody></table></div>"}
function renderInsights(){document.getElementById("insights").innerHTML="<div class='toolbar'><div>选择关键词后点击分析，可自动生成洞察报告并供文案生成使用。</div></div><div class='grid three'>"+state.keywords.map(function(k){return"<div class='card pad'><h3>"+k.keyword+"</h3><p class='sub'>"+k.category+" · "+label(k.status)+"</p><div class='row-actions' style='margin-top:16px'><button class='btn' onclick='collect("+k.id+")'>采集</button><button class='btn primary' onclick='analyze("+k.id+")'>生成洞察</button></div></div>"}).join("")+"</div>"}
function renderGenerate(){var accountOptions=state.accounts.map(function(a){return"<option value='"+a.id+"'>"+a.name+"</option>"}).join("");var keywordOptions=state.keywords.map(function(k){return"<option value='"+k.id+"'>"+k.keyword+"</option>"}).join("");document.getElementById("generate").innerHTML="<div class='card pad' style='max-width:760px'><h3>生成文案</h3><div class='grid' style='margin-top:16px'><div class='field'><label>关键词</label><select id='genKeyword'>"+keywordOptions+"</select></div><div class='field'><label>账号</label><select id='genAccount'>"+accountOptions+"</select></div><div class='field'><label>生成要求</label><textarea id='genInstruction' placeholder='例如：少广告感，加入个人体验'></textarea></div><button class='btn primary' onclick='generateContent()'>生成并提交审核</button></div></div>"}
function renderReview(){var selected=state.selectedContent||state.contents[0];var detail=selected?"<h3>审核详情</h3><p class='sub'>"+selected.title+"</p><div class='preview'>"+selected.body.replaceAll("\n","<br>")+"</div><div class='row-actions'>"+pill(selected.risk_level)+"<span class='pill blue'>重复度 "+Math.round(selected.duplicate_score*100)+"%</span></div><div class='row-actions'><button class='btn primary' onclick='approve("+selected.id+")'>通过</button><button class='btn' onclick='saveDraft("+selected.id+")'>保存草稿</button><button class='btn danger' onclick='openReject("+selected.id+")'>驳回重生</button></div>":"<p class='sub'>暂无内容</p>";document.getElementById("review").innerHTML="<div class='drawer'><div class='card table-wrap'><table><thead><tr><th>标题</th><th>关键词</th><th>账号</th><th>风险</th><th>状态</th><th>操作</th></tr></thead><tbody>"+state.contents.map(function(c){return"<tr><td>"+c.title+"</td><td>"+(c.keyword||"")+"</td><td>"+(c.account_name||"")+"</td><td>"+pill(c.risk_level)+"</td><td>"+pill(c.status)+"</td><td><button class='btn' onclick='selectContent("+c.id+")'>查看</button></td></tr>"}).join("")+"</tbody></table></div><aside class='card pad sidepanel grid'>"+detail+"</aside></div>"}
function renderCalendar(){var days=["周一","周二","周三","周四","周五","周六","周日"];document.getElementById("calendar").innerHTML="<div class='toolbar'><button class='btn primary' onclick='runDue()'>扫描到期发布</button><span class='sub'>可在审核详情里保存草稿后排期</span></div><div class='calendar'>"+days.map(function(day,i){var ev=state.publishTasks.filter(function(p){return new Date(p.scheduled_at).getDay()===(i+1)%7}).map(function(p){return"<div class='event "+clsStatus(p.status)+"'><b>"+fmtTime(p.scheduled_at)+"</b><div>"+(p.title||"")+"</div>"+pill(p.status)+"</div>"}).join("");return"<div class='day'><b>"+day+"</b>"+ev+"</div>"}).join("")+"</div>"}
function renderAccounts(){document.getElementById("accounts").innerHTML="<div class='toolbar'><button class='btn primary' onclick=\"document.getElementById('accountModal').classList.add('open')\">绑定账号</button><span class='sub'>保存真实账号信息；发布能力仍需配置官方授权 endpoint。</span></div><div class='card table-wrap'><table><thead><tr><th>账号</th><th>类型</th><th>授权</th><th>今日排期</th><th>异常状态</th></tr></thead><tbody>"+state.accounts.map(function(a){return"<tr><td>"+a.name+"</td><td>"+a.account_type+"</td><td>"+pill(a.auth_status==='正常'?'running':'error')+"</td><td>"+a.today_scheduled+" / "+a.daily_limit+"</td><td>"+a.exception_status+"</td></tr>"}).join("")+"</tbody></table></div>"}
function renderRules(){var r=state.rules||{};var ai=(state.settings&&state.settings.ai)||{};document.getElementById("rules").innerHTML="<div class='grid two'><div class='card pad grid'><h3>规则设置</h3><div class='field'><label>品牌语气</label><textarea id='ruleVoice'>"+(r.brand_voice||"")+"</textarea></div><div class='field'><label>禁用表达</label><textarea id='ruleBanned'>"+(r.banned_phrases||"")+"</textarea></div><div class='field'><label>审核规则</label><textarea id='ruleReview'>"+(r.review_rules||"")+"</textarea></div><button class='btn primary' onclick='saveRules()'>保存规则</button></div><div class='card pad grid'><h3>系统设置</h3><div class='row-actions'>"+pill(ai.openai_configured?'running':'error')+"<span class='pill blue'>"+(ai.ai_provider||'openai')+"</span></div><div class='field'><label>OpenAI API Key</label><input id='openaiKey' type='password' placeholder='"+(ai.openai_configured?'已配置，留空则不修改':'请输入 API Key')+"'></div><div class='field'><label>OpenAI 模型</label><input id='openaiModel' value='"+(ai.openai_model||'gpt-5.5')+"'></div><div class='field'><label>OpenAI Base URL</label><input id='openaiBaseURL' value='"+(ai.openai_base_url||'https://api.openai.com')+"'></div><button class='btn primary' onclick='saveSettings()'>保存系统设置</button><p class='sub'>默认不绕过平台登录、验证码或风控。采集通过网页登录态或官方接口，分析和文案生成通过 OpenAI API。</p></div></div>"}
function createKeyword(){api('/api/keywords',{method:'POST',body:JSON.stringify({keyword:val('newKeyword'),category:val('newCategory'),sample_limit:Number(val('newLimit'))})}).then(function(){closeModal('keywordModal');toast('关键词已创建');load()}).catch(function(e){toast(e.message)})}
function createAccount(){api('/api/accounts',{method:'POST',body:JSON.stringify({name:val('accountName'),account_type:val('accountType'),auth_status:val('accountAuth'),daily_limit:Number(val('accountLimit')),exception_status:'未验证'})}).then(function(){closeModal('accountModal');toast('账号已保存');load()}).catch(function(e){toast(e.message)})}
function openImport(id){document.getElementById('importKeywordID').value=id;document.getElementById('importMode').value='text';toggleImportMode();document.getElementById('importModal').classList.add('open')}
function toggleImportMode(){var m=val('importMode');document.getElementById('importTextField').style.display=m==='text'?'grid':'none';document.getElementById('importJSONField').style.display=m==='json'?'grid':'none'}
function submitImport(){var id=val('importKeywordID');if(val('importMode')==='text'){return api('/api/keywords/'+id+'/import-text',{method:'POST',body:JSON.stringify({raw_text:val('importRawText')})}).then(function(r){closeModal('importModal');toast('已导入 '+r.length+' 条真实样本');load()}).catch(function(e){toast(e.message)})}var posts;try{posts=JSON.parse(val('importPosts'))}catch(e){return toast('JSON 格式错误：'+e.message)}if(!Array.isArray(posts))return toast('请粘贴 JSON 数组');api('/api/keywords/'+id+'/import',{method:'POST',body:JSON.stringify({posts:posts})}).then(function(r){closeModal('importModal');toast('已导入 '+r.length+' 条样本');load()}).catch(function(e){toast(e.message)})}
function collect(id){api('/api/keywords/'+id+'/collect',{method:'POST'}).then(function(){toast('采集完成');load()}).catch(function(e){toast(e.message)})}
function collectFirst(){if(state.keywords[0])collect(state.keywords[0].id)}
function analyze(id){api('/api/keywords/'+id+'/analyze',{method:'POST'}).then(function(){toast('分析完成');load()}).catch(function(e){toast(e.message)})}
function quickGenerate(id){var account=state.accounts[0];if(!account)return toast('请先配置账号');api('/api/generate',{method:'POST',body:JSON.stringify({keyword_task_id:id,account_id:account.id})}).then(function(){toast('已生成并进入审核');show('review');load()}).catch(function(e){toast(e.message)})}
function generateContent(){api('/api/generate',{method:'POST',body:JSON.stringify({keyword_task_id:Number(val('genKeyword')),account_id:Number(val('genAccount')),instruction:val('genInstruction')})}).then(function(){toast('已生成并进入审核');show('review');load()}).catch(function(e){toast(e.message)})}
function selectContent(id){state.selectedContent=state.contents.find(function(c){return c.id===id});renderReview()}
function approve(id){api('/api/contents/'+id+'/approve',{method:'POST',body:JSON.stringify({reviewer:'小林'})}).then(function(){toast('审核通过');load()}).catch(function(e){toast(e.message)})}
function openReject(id){document.getElementById('rejectID').value=id;document.getElementById('rejectModal').classList.add('open')}
function submitReject(){api('/api/contents/'+val('rejectID')+'/reject',{method:'POST',body:JSON.stringify({reviewer:'小林',reason:val('rejectReason'),instruction:val('rejectInstruction')})}).then(function(){closeModal('rejectModal');toast('已驳回并重新生成');load()}).catch(function(e){toast(e.message)})}
function saveDraft(id){api('/api/contents/'+id+'/save-draft',{method:'POST'}).then(function(c){toast('草稿已保存');var t=new Date(Date.now()+60000);return api('/api/contents/'+c.id+'/schedule',{method:'POST',body:JSON.stringify({scheduled_at:t.toISOString()})})}).then(function(){toast('已排期到 1 分钟后');load()}).catch(function(e){toast(e.message)})}
function runDue(){api('/api/publish/run-due',{method:'POST'}).then(function(r){toast('发布扫描完成：'+r.published+' 条');load()}).catch(function(e){toast(e.message)})}
function saveRules(){var r=state.rules||{};r.brand_voice=val('ruleVoice');r.banned_phrases=val('ruleBanned');r.review_rules=val('ruleReview');api('/api/rules',{method:'PUT',body:JSON.stringify(r)}).then(function(){toast('规则已保存');load()}).catch(function(e){toast(e.message)})}
function saveSettings(){api('/api/settings',{method:'PUT',body:JSON.stringify({ai_provider:'openai',openai_api_key:val('openaiKey'),openai_model:val('openaiModel'),openai_base_url:val('openaiBaseURL')})}).then(function(){toast('系统设置已保存');load()}).catch(function(e){toast(e.message)})}
function val(id){return document.getElementById(id).value}
load();
</script>
</body>
</html>`)
